/**
 * Reconciles ONE staged payment to TWO OR MORE already-recorded gifts for
different donors — the case where a single incoming-money record (e.g. a
Stripe payout that nets fees into a lump sum) covers several donors'
gifts. Each portion links to an existing gift for that gift's own gross
amount; no new gift is minted and QuickBooks is never written back. The
staged row is marked approved (human-confirmed) and its own donor /
single-gift link columns are cleared — its resolution lives entirely in
the split links. Guards: the row is pending; at least two distinct gifts;
each gift exists, carries a single valid donor, and is not already linked
to ANY staged payment (matched, created, group-reconciled, or split); and
the gifts' combined GROSS total sits in the processor fee-band tolerance
around the staged NET amount (sum >= staged - 0.01 AND sum <= staged *
1.1 + 1). Reversible as a whole via the revert endpoint (unsplit).

 * @summary Split one staged payment across several existing gifts (no new gift is created).
 */
export const SplitStagedPaymentParams = zod.object({
  id: zod.coerce.string(),
});

export const splitStagedPaymentBodyGiftIdsMin = 2;

export const SplitStagedPaymentBody = zod
  .object({
    giftIds: zod
      .array(zod.string())
      .min(splitStagedPaymentBodyGiftIdsMin)
      .describe(
        "Ids of the existing gifts to split this staged payment across. Must be at least two distinct gifts, each unlinked everywhere, each with a single valid donor; their combined gross total must sit in the fee-band around the staged net amount.",
      ),
  })
  .describe(
    "Split one staged payment across several existing gifts. Each portion is the linked gift's own gross amount; no new gift is created.",
  );

export const SplitStagedPaymentResponse = zod.object({
  stagedPaymentId: zod.string(),
  giftIds: zod.array(zod.string()),
  splitTotal: zod.string().describe("Combined gross total of the split gifts."),
});

/**
 * Manually groups two or more staged payments into a single unit and
reconciles the GROUP as a whole to one already-recorded gift (typically a
multi-allocation gift). Members must form one coherent group: they share
ONE underlying bank Deposit (same qbDepositId), or — when no deposit was
captured — they share the same payer name (e.g. a single wire, or a
series of stock sales, split across several QuickBooks records). No new
gift is minted and QuickBooks is never written back. Every member is set
to approved with groupReconciledGiftId = the gift; one deterministic
representative member also carries matchedGiftId so the gift shows linked.
The group adopts the gift's donor (Donor XOR). Guards: at least two rows,
all pending and unresolved, all sharing one grouping key (deposit or
payer), the gift exists with a single valid donor and is not already
linked elsewhere, and the members' combined total matches the gift amount
within the processor fee-band tolerance. When the grouped payments do not
all fall on the same date_received, or carry more than one distinct
(non-null) bank deposit, `confirmMultiDate` must be true (otherwise
400 multi_date_confirmation_required) — this guards against collapsing
unrelated same-payer gifts. When the combined total falls OUTSIDE the
fee-band tolerance (e.g. stock/securities gifts whose sale proceeds differ
from the booked value), `confirmAmountMismatch` must be true (otherwise
400 amount_mismatch_confirmation_required). Reversible as a whole via the
revert endpoint.

 * @summary Group several staged payments and reconcile them as one unit to an existing gift.
 */
export const groupReconcileStagedPaymentsBodyStagedPaymentIdsMin = 2;

export const GroupReconcileStagedPaymentsBody = zod
  .object({
    stagedPaymentIds: zod
      .array(zod.string())
      .min(groupReconcileStagedPaymentsBodyStagedPaymentIdsMin)
      .describe(
        "Ids of the staged payments to group. Must be at least two, all pending, and all sharing the same non-null qbDepositId, or — when none has a deposit — the same payer name.",
      ),
    giftId: zod.string().describe("The existing gift the group reconciles to."),
    confirmMultiDate: zod
      .boolean()
      .optional()
      .describe(
        "Must be true when the grouped payments do not all share the same date_received, or carry more than one distinct (non-null) bank deposit. Guards against accidentally collapsing unrelated same-payer gifts (e.g. recurring donations) or two genuinely separate deposits into one. The client prompts the operator to confirm before sending this.",
      ),
    confirmAmountMismatch: zod
      .boolean()
      .optional()
      .describe(
        "Must be true when the members' combined total falls OUTSIDE the processor fee-band tolerance around the gift amount (e.g. stock\/securities gifts, where the cash from selling the shares differs from the gift's booked value). Lets the operator explicitly approve a deliberate amount mismatch; without it such a group is rejected 400 amount_mismatch_confirmation_required. The client prompts the operator to confirm before sending this.",
      ),
  })
  .describe(
    "Group several staged payments and reconcile the whole group to one existing gift. Members must share one bank deposit, or — when no deposit was captured — the same payer.",
  );

