/**
 * Human approval of a reconciliation card. The server RE-DERIVES and
RE-VALIDATES the whole graph (it never trusts UI-supplied locks) and runs the
consistency gate before committing in one transaction: QB present + not already
reconciled; exactly one donor (Donor XOR); gift donor == opportunity donor;
the gift is not already claimed by another evidence row; amount/date within the
fee-band tolerance unless an override reason is given; Stripe GROSS takes
precedence over the QB net when a charge is selected; nothing is archived.
Minting a gift is human-only. Idempotent: re-approving a reconciled card
returns its current state.

 * @summary Approve a card — link or human-mint a gift, enforcing all invariants server-side.
 */
export const ApproveReconciliationCardParams = zod.object({
  stagedPaymentId: zod.coerce.string(),
});

export const ApproveReconciliationCardBody = zod
  .object({
    outcome: zod
      .enum([
        "link_existing_gift",
        "create_gift",
        "create_gift_from_opportunity",
        "convert_to_pledge_and_first_payment",
      ])
      .describe(
        "What approving the card does.\nlink_existing_gift: tie the QB (+Stripe) evidence to an existing gift; no new gift.\ncreate_gift: human-mint a new gift from the QB evidence for the chosen donor.\ncreate_gift_from_opportunity: mint a one-time gift and link it to the chosen opportunity (paymentOnPledgeId); the opp derives to cash_in when fully paid.\nconvert_to_pledge_and_first_payment: latch the opportunity as a pledge (commitment stage, wasPledge) and mint the first-payment gift linked to it.\n",
      ),
    giftId: zod
      .string()
      .nullish()
      .describe("Existing gift to link (required for link_existing_gift)."),
    opportunityId: zod
      .string()
      .nullish()
      .describe(
        "Opportunity\/pledge to generate from or link to (required for the \*_opportunity \/ convert_\* outcomes).",
      ),
    organizationId: zod
      .string()
      .nullish()
      .describe(
        "Donor XOR — set exactly one of the three donor FKs when creating a gift and the donor isn't derivable.",
      ),
    individualGiverPersonId: zod.string().nullish(),
    householdId: zod.string().nullish(),
    paymentIntermediaryId: zod
      .string()
      .nullish()
      .describe(
        "Optional DAF \/ giving-platform conduit the donor gave through.",
      ),
    switchGiftDonor: zod
      .boolean()
      .nullish()
      .describe(
        "For link_existing_gift ONLY: when true, re-point the existing gift's donor to the single donor FK supplied in this body (after explicit human confirmation in the UI). Blocked (409 gift_pledge_donor_conflict) when the gift is a payment on a pledge\/opportunity owned by a different donor — fix the pledge first.",
      ),
    stripeChargeId: zod
      .string()
      .nullish()
      .describe(
        "The Stripe charge whose GROSS becomes the gift's final amount (Stripe precedence). Omit for QB-only money (brokerage\/check).",
      ),
    overrideAmountMismatchReason: zod
      .string()
      .nullish()
      .describe(
        "Required to approve when the evidence amount and the gift amount fall outside the fee-band tolerance.",
      ),
  })
  .describe(
    "Approve a reconciliation card. The server re-derives and re-validates the entire graph and runs the consistency gate before committing; it never trusts UI-supplied locks.",
  );

export const ApproveReconciliationCardResponse = zod.object({
  ok: zod.literal(true),
  outcome: zod
    .enum([
      "link_existing_gift",
      "create_gift",
      "create_gift_from_opportunity",
      "convert_to_pledge_and_first_payment",
    ])
    .describe(
      "What approving the card does.\nlink_existing_gift: tie the QB (+Stripe) evidence to an existing gift; no new gift.\ncreate_gift: human-mint a new gift from the QB evidence for the chosen donor.\ncreate_gift_from_opportunity: mint a one-time gift and link it to the chosen opportunity (paymentOnPledgeId); the opp derives to cash_in when fully paid.\nconvert_to_pledge_and_first_payment: latch the opportunity as a pledge (commitment stage, wasPledge) and mint the first-payment gift linked to it.\n",
    ),
  stagedPaymentId: zod.string(),
  giftId: zod
    .string()
    .describe(
      "The existing-or-newly-created gift the evidence is now tied to.",
    ),
  opportunityId: zod.string().nullish(),
  createdGift: zod.boolean().describe("True when a new gift was minted."),
  createdPledge: zod
    .boolean()
    .describe("True when an opportunity was latched into a pledge."),
});

/**
 * Free search over QuickBooks staged-payment rows by text / amount / date window,
with NO card anchor — used by the stray-Stripe worklist to hunt down the QB
deposit that a yet-unmatched Stripe payout should belong to. Returns qb
candidates (same shape as the card search). Read-only.

 * @summary Criteria-based QuickBooks staged-payment search (not anchored to a card).
 */
export const searchReconciliationQbStagedQueryDaysDefault = 30;
export const searchReconciliationQbStagedQueryDaysMax = 365;

export const searchReconciliationQbStagedQueryLimitDefault = 25;
export const searchReconciliationQbStagedQueryLimitMax = 100;

export const SearchReconciliationQbStagedQueryParams = zod.object({
  q: zod.coerce
    .string()
    .optional()
    .describe("Free-text over payer name \/ reference \/ memo \/ doc number."),
  amount: zod.coerce
    .string()
    .optional()
    .describe(
      "Target amount (major units); when set, results are scored\/filtered around it.",
    ),
  date: zod.coerce
    .string()
    .date()
    .optional()
    .describe("Anchor date; pair with days for a ± window."),
  days: zod.coerce
    .number()
    .min(1)
    .max(searchReconciliationQbStagedQueryDaysMax)
    .default(searchReconciliationQbStagedQueryDaysDefault)
    .describe("± days around date for the amount\/date window."),
  limit: zod.coerce
    .number()
    .min(1)
    .max(searchReconciliationQbStagedQueryLimitMax)
    .default(searchReconciliationQbStagedQueryLimitDefault),
});

export const SearchReconciliationQbStagedResponse = zod.object({
  data: zod.array(
    zod.object({
      nodeType: zod
        .enum(["qb", "donor", "gift", "opportunity"])
        .describe(
          "A node in a reconciliation card's match graph. qb is the required anchor; donor\/gift\/opportunity are the resolvable nodes (opportunity covers pledges — same table). Stripe is evidence, not a node.",
        ),
      id: zod.string(),
      label: zod
        .string()
        .describe(
          "Display label (anonymous-masked when the viewer can't see the identity).",
        ),
      sublabel: zod
        .string()
        .nullish()
        .describe(
          "Secondary context (donor name for a gift\/opp, email\/phone for a donor).",
        ),
      amount: zod.string().nullish(),
      date: zod.string().date().nullish(),
      confidence: zod
        .number()
        .nullish()
        .describe("0–100 match confidence; null for filter-only candidates."),
      source: zod
        .enum([
          "donor_xor",
          "payment_on_pledge",
          "name",
          "email",
          "amount_date",
          "memo",
          "intermediary",
          "stripe",
          "manual",
        ])
        .nullish()
        .describe("How a candidate was derived (audit + UI badge)."),
      donorKind: zod.enum(["organization", "person", "household"]).nullish(),
      donorId: zod
        .string()
        .nullish()
        .describe(
          "For gift\/opportunity candidates: the record id of the candidate's CURRENT donor (organization\/person\/household), so the client can detect when a picked donor differs from the gift's existing donor.",
        ),
      alreadyLinkedStagedPaymentId: zod
        .string()
        .nullish()
        .describe(
          "For gift candidates: set when the gift is already reconciled\/created\/group\/split-linked by another staged payment (UI disables linking to avoid double-counting).",
        ),
      conflictReason: zod
        .string()
        .nullish()
        .describe(
          "Why this candidate conflicts with a locked node (set only when state=conflict).",
        ),
    }),
  ),
});

/**
 * Every gift is expected to carry a QuickBooks record; this lists the gifts that
do not — i.e. no staged-payment row links the gift (matched / created /
group-reconciled) and the gift has no final-amount QB pointer. Broad by design
(cash / check / brokerage / imports all surface) with filters to slice. Donor
names are anonymous-masked for the viewer. Read-only.

 * @summary Gifts with no QuickBooks record (data-quality worklist).
 */
export const listGiftsMissingQbQueryLimitDefault = 50;
export const listGiftsMissingQbQueryLimitMax = 200;

export const listGiftsMissingQbQueryOffsetDefault = 0;
export const listGiftsMissingQbQueryOffsetMin = 0;

export const ListGiftsMissingQbQueryParams = zod.object({
  q: zod.coerce
    .string()
    .optional()
    .describe(
      "Free-text over donor name (organization \/ person \/ household).",
    ),
  entityId: zod.coerce
    .string()
    .optional()
    .describe("Filter to one Wildflower legal entity."),
  paymentMethod: zod
    .enum([
      "ach",
      "check",
      "wire",
      "stock",
      "donor_box",
      "daf_ach",
      "daf_check",
      "daf_bill_com",
    ])
    .optional()
    .describe("Filter to one payment method."),
  hasStripe: zod.coerce
    .boolean()
    .optional()
    .describe(
      "true: only QB-missing gifts that DO carry a Stripe charge (high-priority anomaly); false: only gifts with neither QB nor Stripe.",
    ),
  dateFrom: zod.coerce.string().date().optional(),
  dateTo: zod.coerce.string().date().optional(),
  limit: zod.coerce
    .number()
    .min(1)
    .max(listGiftsMissingQbQueryLimitMax)
    .default(listGiftsMissingQbQueryLimitDefault),
  offset: zod.coerce
    .number()
    .min(listGiftsMissingQbQueryOffsetMin)
    .default(listGiftsMissingQbQueryOffsetDefault),
});

export const ListGiftsMissingQbResponse = zod.object({
  data: zod.array(
    zod
      .object({
        id: zod.string(),
        donorName: zod
          .string()
          .nullish()
          .describe("Donor display name (anonymous-masked for the viewer)."),
        donorKind: zod.enum(["organization", "person", "household"]).nullish(),
        amount: zod.string().nullish(),
        dateReceived: zod.string().date().nullish(),
        paymentMethod: zod
          .enum([
            "ach",
            "check",
            "wire",
            "stock",
            "donor_box",
            "daf_ach",
            "daf_check",
            "daf_bill_com",
          ])
          .nullish(),
        entityId: zod.string().nullish(),
        entityName: zod.string().nullish(),
        finalAmountSource: zod
          .enum(["human", "stripe", "quickbooks"])
          .nullish()
          .describe(
            "Where a gift's final `amount` was last sourced from. human: hand-entered, never reconciled. stripe: stamped from a Stripe charge (gross). quickbooks: stamped from a QuickBooks staged row. XOR with the two final_amount pointer fields.",
          ),
        hasStripeEvidence: zod
          .boolean()
          .describe(
            "True when a Stripe charge backs this gift even though no QB record does (a high-priority anomaly).",
          ),
      })
      .describe(
        "A gift with no QuickBooks record — list item for the gifts-missing-QB worklist.",
      ),
  ),
  pagination: zod.object({
    page: zod.number(),
    limit: zod.number(),
    total: zod.number(),
  }),
});
